package com.alibaba.fastjson2.writer;

import com.alibaba.fastjson2.JSONWriter;

import java.lang.reflect.Type;

final class ObjectWriterImplClass
        extends ObjectWriterPrimitiveImpl {
    static final ObjectWriterImplClass INSTANCE = new ObjectWriterImplClass();

    @Override
    public void writeJSONB(JSONWriter jsonWriter, Object object, Object fieldName, Type fieldType, long features) {
        if (object == null) {
            jsonWriter.writeNull();
            return;
        }

        if (jsonWriter.isWriteTypeInfo(object, fieldType, features)) {
            jsonWriter.writeTypeName("java.lang.Class");
        }

        Class clazz = (Class) object;
        jsonWriter.writeString(clazz.getName());
    }

    @Override
    public void write(JSONWriter jsonWriter, Object object, Object fieldName, Type fieldType, long features) {
        if (object == null) {
            jsonWriter.writeNull();
            return;
        }
        Class clazz = (Class) object;
        jsonWriter.writeString(
                clazz.getName());
    }
}

package com.alibaba.fastjson2.writer;

import com.alibaba.fastjson2.JSONPObject;
import com.alibaba.fastjson2.JSONWriter;

import java.lang.reflect.Type;
import java.util.List;

public class ObjectWriterImplJSONP
        extends ObjectWriterPrimitiveImpl<JSONPObject> {
    @Override
    public void write(JSONWriter jsonWriter, Object object, Object fieldName, Type fieldType, long features) {
        long features1 = jsonWriter.getFeatures(features);
        if ((features1 & JSONWriter.Feature.BrowserSecure.mask) != 0) {
            final String SECURITY_PREFIX = "/**/";
            jsonWriter.writeRaw(SECURITY_PREFIX);
        }

        JSONPObject jsonp = (JSONPObject) object;
        jsonWriter.writeRaw(jsonp.getFunction());
        jsonWriter.writeRaw('(');
        List<Object> parameters = jsonp.getParameters();
        for (int i = 0; i < parameters.size(); ++i) {
            if (i != 0) {
                jsonWriter.writeRaw(',');
            }
            jsonWriter.writeAny(parameters.get(i));
        }
        jsonWriter.writeRaw(')');
    }
}

package com.alibaba.fastjson2.support.odps;

import com.alibaba.fastjson2.JSON;
import com.alibaba.fastjson2.JSONPath;
import com.alibaba.fastjson2.JSONReader;
import com.aliyun.odps.udf.UDF;

public class JSONExtract2
        extends UDF {
    public String evaluate(String json, String path) {
        if (json == null || json.isEmpty()) {
            return null;
        }

        Object result = null;
        try (JSONReader jsonReader = JSONReader.of(json)) {
            result = JSONPath.of(path)
                    .extract(jsonReader);
        } catch (Throwable ignored) {
            // ignored
        }

        if (result == null) {
            return null;
        }
        try {
            return JSON.toJSONString(result);
        } catch (Exception e) {
            return null;
        }
    }
}

